#include<bits/stdc++.h>
using namespace std;
int n, a[300], dp[300][300], maxn = INT_MIN;

int main() {
	cin >> n;
	for (int i = 1; i <= n; i++) {
		cin >> a[i];
		a[i + n] = a[i];
	}
	for (int i = 2; i < 2 * n; i++) {
		for (int j = i - 1; i - j < n && j >= 1; j--) {
			for (int k = j; k < i; k++) {
				dp[j][i] = max(dp[j][i], dp[j][k] + dp[k + 1][i] + a[j] * a[k + 1] * a[i + 1]);
			}
			if (dp[j][i] > maxn) {
				maxn = dp[j][i];
			}
		}
	}
	cout << maxn;
	return 0;
}
